import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def euclidean_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    def calculate_score(customer_pos, time_window, current_time):
        distance = euclidean_distance(cur_truck_pos, customer_pos)
        arrival_time = current_time + distance / truck_speed
        wait_time = max(0, time_window[0] - arrival_time)

        if arrival_time > time_window[1]:
            return float('-inf')

        urgency = max(0, 1 / (time_window[1] - current_time + 1e-5))
        distance_to_depot = euclidean_distance(customer_pos, depot_pos)
        score = -distance + urgency - wait_time + (-distance_to_depot * 0.1)
        return score

    scores = [calculate_score(unvisited_customers[i], time_windows[i], current_time) for i in range(len(unvisited_customers))]
    best_node = max(range(len(unvisited_customers)), key=lambda i: scores[i])

    return best_node
